SELECT log_id, user_id, problem_id, user_answer, is_correct, solved_time, solved_date
FROM quiz_log
WHERE user_id = #{userId}
  AND problem_id = #{problemId}
  AND solved_date = #{solvedDate}

SELECT COUNT(*) > 0
FROM quiz_log
WHERE user_id = #{userId}
  AND solved_date = #{solvedDate}

SELECT COUNT(*) > 0
FROM quiz_log
WHERE user_id = #{userId}
  AND problem_id = #{problemId}

SELECT log_id, user_id, problem_id, user_answer, is_correct, solved_time, solved_date
FROM quiz_log
WHERE user_id = #{userId}
ORDER BY solved_time DESC
LIMIT #{limit}
